const numbersToWords=N=>{const S=['','ένα','δύο','τρία','τέσσερα','πέντε','έξι','επτά','οκτώ','εννέα','δέκα','έντεκα','δώδεκα','δεκατρία','δεκατέσσερα','δεκαπέντε','δεκαέξι','δεκαεπτά','δεκαοκτώ','δεκαεννέα'];if(N<0x14)return S[N];if(N<0x64)return['','','είκοσι','τριάντα','σαράντα','πενήντα','εξήντα','εβδομήντα','ογδόντα','ενενήντα'][Math['floor'](N/0xa)]+(N%0xa?'\x20'+S[N%0xa]:'');if(N<0x3e8){const U=Math['floor'](N/0x64),u=N%0x64;return(0x1===U?'εκατό':0x2===U?'διακόσια':0x3===U?'τριακόσια':0x4===U?'τετρακόσια':0x5===U?'πεντακόσια':0x6===U?'εξακόσια':0x7===U?'επτακόσια':0x8===U?'οκτακόσια':0x9===U?'εννιακόσια':'')+(u?'\x20'+numbersToWords(u):'');}return N<0xf4240?numbersToWords(Math['floor'](N/0x3e8))+'\x20χιλιάδες'+(N%0x3e8?'\x20'+numbersToWords(N%0x3e8):''):numbersToWords(Math['floor'](N/0xf4240))+'\x20εκατομμύρια'+(N%0xf4240?'\x20'+numbersToWords(N%0xf4240):'');},numberToText=(N,S='money')=>{const U=Math['floor'](N),u=Math['round'](0x64*(N-U));let D=numbersToWords(U),H=u>0x0?numbersToWords(u):'';switch(S){case'money':return H?D+'\x20ευρώ\x20και\x20'+H+'\x20λεπτά':D+'\x20ευρώ';case'time':return H?D+'\x20ώρες\x20και\x20'+H+'\x20λεπτά':D+'\x20ώρες';default:return H?D+'\x20και\x20'+H:''+D;}};